settings:
  auto_execute_hooks: true
hooks: {}

{
  "name": "@ifi/pi-spec",
  "version": "0.4.4",
  "description": "Native spec-kit workflow for pi with a /spec command, TypeScript scaffolding, and spec-driven prompts.",
  "type": "module",
  "keywords": [
    "pi-package",
    "pi",
    "pi-coding-agent",
    "spec",
    "spec-driven-development",
    "requirements",
    "workflow"
  ],
  "pi": {
    "extensions": [
      "./extension/index.ts"
    ]
  },
  "exports": {
    "./package.json": "./package.json"
  },
  "files": [
    "extension",
    "README.md",
    "!**/*.test.ts"
  ],
  "license": "MIT",
  "repository": {
    "type": "git",
    "url": "git+https://github.com/ifiokjr/oh-pi.git",
    "directory": "packages/spec"
  },
  "homepage": "https://github.com/ifiokjr/oh-pi/tree/main/packages/spec",
  "bugs": {
    "url": "https://github.com/ifiokjr/oh-pi/issues"
  },
  "scripts": {
    "build": "pnpm run typecheck && pnpm run test:worktree",
    "typecheck": "tsgo --project ./tsconfig.json --noEmit",
    "test:worktree": "vitest run --config ./vitest.worktree.config.ts"
  },
  "peerDependencies": {
    "@mariozechner/pi-agent-core": ">=0.56.1",
    "@mariozechner/pi-ai": ">=0.56.1",
    "@mariozechner/pi-coding-agent": ">=0.56.1",
    "@mariozechner/pi-tui": ">=0.56.1",
    "@sinclair/typebox": "*"
  }
}

import type { ExtensionAPI, ExtensionCommandContext } from "@mariozechner/pi-coding-agent";
import { Text } from "@mariozechner/pi-tui";
import { createVcsClient } from "./vcs.js";
import { buildWorkflowPrompt, getStepNotes } from "./prompts.js";
import {
	ensureFeatureArtifacts,
	ensurePlanArtifact,
	ensureWorkflowScaffold,
	formatCreatedFiles,
	getWorkflowTemplatePath,
} from "./scaffold.js";
import {
	buildWorkflowStatus,
	formatFeatureList,
	formatHelpReport,
	formatWorkflowStatus,
	summarizeChecklists,
} from "./status.js";
import { SPEC_SUBCOMMANDS, type SpecSubcommand, type WorkflowPaths, type WorkflowStep } from "./types.js";
import {
	buildWorkflowPaths,
	findRepoRoot,
	getLatestFeatureDir,
	listFeatureDirs,
	prepareFeatureWorkspace,
	resolveFeatureFromBranch,
} from "./workspace.js";

const REPORT_MESSAGE_TYPE = "pi-spec-report";
const PROMPT_OPTIONAL_STEPS = new Set<WorkflowStep>(["clarify", "tasks", "analyze", "implement"]);

function tokenize(input: string): { subcommand: SpecSubcommand | null; remainder: string } {
	const trimmed = input.trim();
	if (!trimmed) {
		return { subcommand: "status", remainder: "" };
	}
	const [raw, ...rest] = trimmed.split(/\s+/);
	const normalized = raw.toLowerCase();
	if ((SPEC_SUBCOMMANDS as readonly string[]).includes(normalized)) {
		return { subcommand: normalized as SpecSubcommand, remainder: rest.join(" ").trim() };
	}
	return { subcommand: null, remainder: trimmed };
}

function sendReport(pi: ExtensionAPI, content: string): void {
	pi.sendMessage({ customType: REPORT_MESSAGE_TYPE, content, display: true });
}

function isWorkflowStep(subcommand: SpecSubcommand): subcommand is WorkflowStep {
	return ["constitution", "specify", "clarify", "checklist", "plan", "tasks", "analyze", "implement"].includes(
		subcommand,
	);
}

async function promptForMissingInput(
	ctx: ExtensionCommandContext,
	title: string,
	placeholder: string,
): Promise<string | undefined> {
	if (!ctx.hasUI) {
		return undefined;
	}
	if (typeof ctx.ui.editor === "function") {
		const response = await ctx.ui.editor(title, placeholder);
		return response?.trim() || undefined;
	}
	if (typeof ctx.ui.input === "function") {
		const response = await ctx.ui.input(title, placeholder);
		return response?.trim() || undefined;
	}
	return undefined;
}

function stepNeedsRequiredInput(step: WorkflowStep): boolean {
	return !PROMPT_OPTIONAL_STEPS.has(step);
}

async function resolveActiveFeatureName(
	ctx: ExtensionCommandContext,
	repoRoot: string,
	currentBranch: string,
	hasGit = true,
): Promise<string | undefined> {
	const featureFromBranch = resolveFeatureFromBranch(repoRoot, currentBranch);
	if (featureFromBranch) {
		return featureFromBranch;
	}

	// When git is available, the current branch is the source of truth for the
	// active feature — matching upstream spec-kit behavior.  The specs/ directory
	// scan is only a fallback for non-git repositories where branch detection is
	// unavailable.
	if (hasGit) {
		return undefined;
	}

	const features = listFeatureDirs(repoRoot);
	if (features.length === 0) {
		return undefined;
	}
	if (features.length === 1) {
		return features[0];
	}
	if (!ctx.hasUI || typeof ctx.ui.select !== "function") {
		return getLatestFeatureDir(repoRoot);
	}
	const selected = await ctx.ui.select("Select active spec feature", features);
	return selected || undefined;
}

async function resolveFeaturePaths(
	ctx: ExtensionCommandContext,
	repoRoot: string,
	currentBranch: string,
	hasGit = true,
): Promise<WorkflowPaths | undefined> {
	const featureName = await resolveActiveFeatureName(ctx, repoRoot, currentBranch, hasGit);
	if (!featureName) {
		ctx.ui.notify("No active feature found. Run /spec specify <feature description> first.", "warning");
		return undefined;
	}
	return buildWorkflowPaths(repoRoot, featureName);
}

function queueWorkflow(
	pi: ExtensionAPI,
	step: WorkflowStep,
	currentBranch: string,
	paths: WorkflowPaths,
	input: string,
): void {
	const prompt = buildWorkflowPrompt({
		step,
		input,
		paths,
		currentBranch,
		workflowTemplatePath: getWorkflowTemplatePath(paths, step),
		stepNotes: getStepNotes(step),
		checklists: step === "implement" ? summarizeChecklists(paths.checklistsDir) : undefined,
	});
	pi.sendUserMessage(prompt);
}

async function collectStepInput(ctx: ExtensionCommandContext, step: WorkflowStep, existing: string): Promise<string> {
	if (existing.trim() || !stepNeedsRequiredInput(step)) {
		return existing.trim();
	}

	const titleByStep: Record<WorkflowStep, string> = {
		constitution: "Describe the constitution principles",
		specify: "Describe the feature to specify",
		clarify: "Optional clarification focus",
		checklist: "Optional checklist focus or domain",
		plan: "Describe the technical context",
		tasks: "Optional task-generation context",
		analyze: "Optional analysis focus",
		implement: "Optional implementation focus",
	};

	return (
		(await promptForMissingInput(ctx, titleByStep[step], "Write the details for this /spec step here")) ?? ""
	).trim();
}

function makeEnv(ctx: ExtensionCommandContext, git = createVcsClient(ctx.cwd)) {
	const { repoRoot, hasGit } = findRepoRoot(ctx.cwd, git);
	const currentBranch = git.getCurrentBranch(repoRoot) ?? process.env.SPECIFY_FEATURE ?? "main";
	const basePaths = buildWorkflowPaths(repoRoot);
	return { git, repoRoot, hasGit, currentBranch, basePaths };
}

function handleInit(pi: ExtensionAPI, repoRoot: string, created: string[]): void {
	sendReport(
		pi,
		[
			"# /spec init",
			"",
			`- Repository root: ${repoRoot}`,
			formatCreatedFiles(created),
			"",
			"Next: `/spec constitution <principles>` or `/spec specify <feature description>`.",
		].join("\n"),
	);
}

async function handleStatus(
	pi: ExtensionAPI,
	ctx: ExtensionCommandContext,
	repoRoot: string,
	currentBranch: string,
	hasGit: boolean,
): Promise<void> {
	const activeFeature = await resolveActiveFeatureName(ctx, repoRoot, currentBranch, hasGit);
	sendReport(
		pi,
		formatWorkflowStatus(
			buildWorkflowStatus({
				repoRoot,
				currentBranch,
				paths: buildWorkflowPaths(repoRoot, activeFeature),
				activeFeature,
			}),
		),
	);
}

async function handleNext(
	pi: ExtensionAPI,
	ctx: ExtensionCommandContext,
	repoRoot: string,
	currentBranch: string,
	hasGit: boolean,
): Promise<void> {
	const activeFeature = await resolveActiveFeatureName(ctx, repoRoot, currentBranch, hasGit);
	const status = buildWorkflowStatus({
		repoRoot,
		currentBranch,
		paths: buildWorkflowPaths(repoRoot, activeFeature),
		activeFeature,
	});
	sendReport(pi, `# Next /spec steps\n\n${status.nextSteps.map((step) => `- ${step}`).join("\n")}`);
}

function handleSpecify(
	pi: ExtensionAPI,
	ctx: ExtensionCommandContext,
	env: ReturnType<typeof makeEnv>,
	input: string,
): void {
	if (!input) {
		ctx.ui.notify("/spec specify requires a feature description.", "warning");
		return;
	}

	try {
		const prepared = prepareFeatureWorkspace({
			repoRoot: env.repoRoot,
			description: input,
			git: env.git,
			currentBranch: env.currentBranch,
			hasGit: env.hasGit,
		});
		const paths = buildWorkflowPaths(env.repoRoot, prepared.branchName);
		ensureWorkflowScaffold(paths);
		ensureFeatureArtifacts(paths);
		queueWorkflow(pi, "specify", prepared.branchName, paths, input);
		sendReport(
			pi,
			[
				"# /spec specify",
				"",
				`- Feature branch: ${prepared.branchName}`,
				`- Feature number: ${prepared.featureNumber}`,
				`- Feature directory: ${prepared.featureDir}`,
				`- Spec file: ${prepared.specFile}`,
				"",
				"Queued the native specification workflow as a user message.",
			].join("\n"),
		);
	} catch (error) {
		ctx.ui.notify(
			`Failed to prepare feature workspace: ${error instanceof Error ? error.message : String(error)}`,
			"error",
		);
	}
}

async function confirmChecklistOverride(ctx: ExtensionCommandContext, paths: WorkflowPaths): Promise<boolean> {
	const checklists = summarizeChecklists(paths.checklistsDir);
	if (
		!(checklists.some((checklist) => checklist.incomplete > 0) && ctx.hasUI && typeof ctx.ui.confirm === "function")
	) {
		return true;
	}

	const proceed = await ctx.ui.confirm(
		"Incomplete spec checklists",
		`${checklists.map((checklist) => `${checklist.name}: ${checklist.incomplete} incomplete item(s)`).join("\n")}

Proceed with implementation anyway?`,
	);
	if (!proceed) {
		ctx.ui.notify("Implementation cancelled until the checklist review is complete.", "info");
	}
	return proceed;
}

async function handleWorkflowStep(
	pi: ExtensionAPI,
	ctx: ExtensionCommandContext,
	env: ReturnType<typeof makeEnv>,
	step: WorkflowStep,
	input: string,
): Promise<void> {
	if (step === "specify") {
		handleSpecify(pi, ctx, env, input);
		return;
	}

	const featurePaths =
		step === "constitution"
			? buildWorkflowPaths(
					env.repoRoot,
					await resolveActiveFeatureName(ctx, env.repoRoot, env.currentBranch, env.hasGit),
				)
			: await resolveFeaturePaths(ctx, env.repoRoot, env.currentBranch, env.hasGit);
	ensureWorkflowScaffold(featurePaths ?? env.basePaths);
	if (!featurePaths) {
		return;
	}

	if (step === "plan") {
		ensurePlanArtifact(featurePaths);
	}
	if (step === "implement" && !(await confirmChecklistOverride(ctx, featurePaths))) {
		return;
	}

	queueWorkflow(pi, step, env.currentBranch, featurePaths, input);
	ctx.ui.notify(`Queued /spec ${step} workflow.`, "info");
}

export default function specExtension(pi: ExtensionAPI) {
	pi.registerMessageRenderer(REPORT_MESSAGE_TYPE, (message, _options, theme) => {
		const text = `${theme.fg("accent", theme.bold("spec"))}\n\n${String(message.content ?? "")}`;
		return new Text(text, 0, 0);
	});

	pi.registerCommand("spec", {
		description:
			"Native spec-kit workflow for pi (/spec init|constitution|specify|clarify|checklist|plan|tasks|analyze|implement)",
		getArgumentCompletions(prefix) {
			const trimmed = prefix.trimStart();
			if (trimmed.includes(" ")) {
				return null;
			}
			const values = SPEC_SUBCOMMANDS.filter((command) => command.startsWith(trimmed)).map((command) => ({
				value: command,
				label: command,
			}));
			return values.length > 0 ? values : null;
		},
		handler: async (rawArgs, ctx) => {
			const { subcommand, remainder } = tokenize(rawArgs);
			if (!subcommand) {
				ctx.ui.notify(`Unknown /spec subcommand: ${rawArgs.trim()}`, "warning");
				sendReport(pi, formatHelpReport());
				return;
			}

			const env = makeEnv(ctx);
			if (subcommand === "init") {
				handleInit(pi, env.repoRoot, ensureWorkflowScaffold(env.basePaths));
				return;
			}
			if (subcommand === "help") {
				sendReport(pi, formatHelpReport());
				return;
			}
			if (subcommand === "list") {
				sendReport(pi, formatFeatureList(env.repoRoot));
				return;
			}
			if (subcommand === "status") {
				await handleStatus(pi, ctx, env.repoRoot, env.currentBranch, env.hasGit);
				return;
			}
			if (subcommand === "next") {
				await handleNext(pi, ctx, env.repoRoot, env.currentBranch, env.hasGit);
				return;
			}
			if (!isWorkflowStep(subcommand)) {
				sendReport(pi, formatHelpReport());
				return;
			}

			const input = await collectStepInput(ctx, subcommand, remainder);
			await handleWorkflowStep(pi, ctx, env, subcommand, input);
		},
	});
}

/**
<!-- {=piSpecSubcommandsDocs} -->

Canonical `/spec` subcommands exposed by the extension. Keep README command lists and exported type
metadata in sync with this source of truth: `status`, `help`, `init`, `constitution`, `specify`,
`clarify`, `checklist`, `plan`, `tasks`, `analyze`, `implement`, `list`, and `next`.

<!-- {/piSpecSubcommandsDocs} -->
*/
export const SPEC_SUBCOMMANDS = [
	"status",
	"help",
	"init",
	"constitution",
	"specify",
	"clarify",
	"checklist",
	"plan",
	"tasks",
	"analyze",
	"implement",
	"list",
	"next",
] as const;

export type SpecSubcommand = (typeof SPEC_SUBCOMMANDS)[number];

/**
<!-- {=piSpecWorkflowStepsDocs} -->

Workflow steps that hand work back into pi for feature execution. These ordered steps are
`constitution`, `specify`, `clarify`, `checklist`, `plan`, `tasks`, `analyze`, and `implement`.
Keep contributor-facing docs aligned with the same sequence.

<!-- {/piSpecWorkflowStepsDocs} -->
*/
export const WORKFLOW_STEPS = [
	"constitution",
	"specify",
	"clarify",
	"checklist",
	"plan",
	"tasks",
	"analyze",
	"implement",
] as const;

export type WorkflowStep = (typeof WORKFLOW_STEPS)[number];

export interface WorkflowPaths {
	repoRoot: string;
	specsDir: string;
	specifyDir: string;
	templatesDir: string;
	memoryDir: string;
	constitutionFile: string;
	agentContextFile: string;
	extensionsConfigFile: string;
	workflowReadmeFile: string;
	featureDir?: string;
	featureBranch?: string;
	featureNumber?: string;
	featureSpec?: string;
	planFile?: string;
	tasksFile?: string;
	researchFile?: string;
	dataModelFile?: string;
	quickstartFile?: string;
	contractsDir?: string;
	checklistsDir?: string;
}

export interface WorkflowStatus {
	initialized: boolean;
	repoRoot: string;
	currentBranch: string;
	featureDirs: string[];
	activeFeature?: string;
	paths: WorkflowPaths;
	artifacts: Array<{ label: string; path: string; exists: boolean }>;
	checklists: ChecklistSummary[];
	nextSteps: string[];
}

export interface ChecklistSummary {
	name: string;
	path: string;
	total: number;
	completed: number;
	incomplete: number;
	status: "pass" | "fail";
}

export interface PreparedFeature {
	branchName: string;
	featureNumber: string;
	featureDir: string;
	specFile: string;
	checklistsDir: string;
	createdBranch: boolean;
}

export interface WorkflowPromptContext {
	step: WorkflowStep;
	input: string;
	paths: WorkflowPaths;
	currentBranch: string;
	workflowTemplatePath: string;
	stepNotes: string[];
	checklists?: ChecklistSummary[];
}

import { existsSync, mkdirSync, readdirSync, statSync } from "node:fs";
import path from "node:path";
import type { GitClient } from "./git.js";
import type { PreparedFeature, WorkflowPaths } from "./types.js";

const STOP_WORDS = new Set([
	"a",
	"an",
	"and",
	"add",
	"are",
	"as",
	"at",
	"be",
	"been",
	"being",
	"by",
	"can",
	"could",
	"did",
	"do",
	"does",
	"for",
	"from",
	"get",
	"had",
	"has",
	"have",
	"i",
	"in",
	"is",
	"it",
	"may",
	"might",
	"must",
	"my",
	"need",
	"of",
	"on",
	"or",
	"our",
	"set",
	"shall",
	"should",
	"that",
	"the",
	"their",
	"these",
	"this",
	"those",
	"to",
	"want",
	"was",
	"were",
	"will",
	"with",
	"would",
	"your",
]);

export function findRepoRoot(cwd: string, git: GitClient): { repoRoot: string; hasGit: boolean } {
	const gitRoot = git.getRepoRoot(cwd);
	if (gitRoot) {
		return { repoRoot: gitRoot, hasGit: true };
	}

	let current = path.resolve(cwd);
	while (true) {
		if (existsSync(path.join(current, ".specify"))) {
			return { repoRoot: current, hasGit: false };
		}
		const parent = path.dirname(current);
		if (parent === current) {
			return { repoRoot: path.resolve(cwd), hasGit: false };
		}
		current = parent;
	}
}

export function listFeatureDirs(repoRoot: string): string[] {
	const specsDir = path.join(repoRoot, "specs");
	if (!existsSync(specsDir)) {
		return [];
	}

	return readdirSync(specsDir)
		.filter((entry) => /^\d{3}-/.test(entry))
		.filter((entry) => {
			const fullPath = path.join(specsDir, entry);
			return existsSync(fullPath) && statSync(fullPath).isDirectory();
		})
		.sort((a, b) => a.localeCompare(b));
}

export function getLatestFeatureDir(repoRoot: string): string | undefined {
	const features = listFeatureDirs(repoRoot);
	return features.at(-1);
}

export function extractFeatureNumber(value: string): number | null {
	const match = value.match(/^(\d{3})-/);
	if (!match) {
		return null;
	}
	return Number.parseInt(match[1], 10);
}

export function resolveFeatureFromBranch(repoRoot: string, branchName: string): string | undefined {
	const prefix = branchName.match(/^(\d{3})-/)?.[1];
	if (!prefix) {
		return undefined;
	}
	const matches = listFeatureDirs(repoRoot).filter((entry) => entry.startsWith(`${prefix}-`));
	if (matches.length === 1) {
		return matches[0];
	}
	return matches.find((entry) => entry === branchName) ?? undefined;
}

export function buildWorkflowPaths(repoRoot: string, featureName?: string): WorkflowPaths {
	const specifyDir = path.join(repoRoot, ".specify");
	const templatesDir = path.join(specifyDir, "templates");
	const memoryDir = path.join(specifyDir, "memory");
	const featureDir = featureName ? path.join(repoRoot, "specs", featureName) : undefined;
	return {
		repoRoot,
		specsDir: path.join(repoRoot, "specs"),
		specifyDir,
		templatesDir,
		memoryDir,
		constitutionFile: path.join(memoryDir, "constitution.md"),
		agentContextFile: path.join(memoryDir, "pi-agent.md"),
		extensionsConfigFile: path.join(specifyDir, "extensions.yml"),
		workflowReadmeFile: path.join(specifyDir, "README.md"),
		featureDir,
		featureBranch: featureName,
		featureNumber: featureName?.match(/^(\d{3})-/)?.[1],
		featureSpec: featureDir ? path.join(featureDir, "spec.md") : undefined,
		planFile: featureDir ? path.join(featureDir, "plan.md") : undefined,
		tasksFile: featureDir ? path.join(featureDir, "tasks.md") : undefined,
		researchFile: featureDir ? path.join(featureDir, "research.md") : undefined,
		dataModelFile: featureDir ? path.join(featureDir, "data-model.md") : undefined,
		quickstartFile: featureDir ? path.join(featureDir, "quickstart.md") : undefined,
		contractsDir: featureDir ? path.join(featureDir, "contracts") : undefined,
		checklistsDir: featureDir ? path.join(featureDir, "checklists") : undefined,
	};
}

export function cleanBranchSegment(value: string): string {
	return value
		.toLowerCase()
		.replace(/[^a-z0-9]+/g, "-")
		.replace(/-+/g, "-")
		.replace(/^-|-$/g, "");
}

export function generateBranchShortName(description: string): string {
	const tokens = description.match(/[A-Za-z0-9]+/g) ?? [];
	const meaningful: string[] = [];

	for (const original of tokens) {
		const normalized = original.toLowerCase();
		if (!normalized || STOP_WORDS.has(normalized)) {
			continue;
		}

		const isAcronymLike = /[A-Z]{2,}/.test(original) || /\d/.test(original);
		if (normalized.length >= 3 || isAcronymLike) {
			meaningful.push(normalized);
		}
	}

	const selected = (meaningful.length > 0 ? meaningful : tokens.map((token) => token.toLowerCase()))
		.filter(Boolean)
		.slice(0, meaningful.length === 4 ? 4 : 3);

	const fallback = selected.join("-") || "feature";
	return cleanBranchSegment(fallback) || "feature";
}

export function truncateBranchName(branchName: string): string {
	const MAX_BRANCH_LENGTH = 244;
	if (branchName.length <= MAX_BRANCH_LENGTH) {
		return branchName;
	}
	const prefix = branchName.slice(0, 4);
	const suffix = branchName.slice(4, MAX_BRANCH_LENGTH).replace(/-+$/g, "");
	return `${prefix}${suffix}`;
}

export function computeNextFeatureNumber(repoRoot: string, branches: string[]): number {
	const featureNumbers = [
		...listFeatureDirs(repoRoot)
			.map((entry) => extractFeatureNumber(entry))
			.filter((value): value is number => value != null),
		...branches
			.map((entry) => entry.replace(/^[^/]+\//, ""))
			.map((entry) => extractFeatureNumber(entry))
			.filter((value): value is number => value != null),
	];
	const highest = featureNumbers.length > 0 ? Math.max(...featureNumbers) : 0;
	return highest + 1;
}

export function prepareFeatureWorkspace(options: {
	repoRoot: string;
	description: string;
	git: GitClient;
	currentBranch: string;
	hasGit: boolean;
	shortName?: string;
}): PreparedFeature {
	const featureNumber = String(
		computeNextFeatureNumber(options.repoRoot, options.git.listBranches(options.repoRoot)),
	).padStart(3, "0");
	const branchSuffix =
		cleanBranchSegment(options.shortName || generateBranchShortName(options.description)) || "feature";
	const branchName = truncateBranchName(`${featureNumber}-${branchSuffix}`);
	const featureDir = path.join(options.repoRoot, "specs", branchName);
	const specFile = path.join(featureDir, "spec.md");
	const checklistsDir = path.join(featureDir, "checklists");

	mkdirSync(featureDir, { recursive: true });
	mkdirSync(checklistsDir, { recursive: true });

	let createdBranch = false;
	if (options.hasGit) {
		if (options.currentBranch !== branchName) {
			options.git.createAndSwitchBranch(options.repoRoot, branchName);
			createdBranch = true;
		}
	}

	return {
		branchName,
		featureNumber,
		featureDir,
		specFile,
		checklistsDir,
		createdBranch,
	};
}

