import { createHash } from "node:crypto";
import { existsSync, readFileSync, writeFileSync } from "node:fs";
import path from "node:path";
import type { LinearMetadata } from "./types.js";

/**
 * Compute SHA-256 hash of content for change detection
 */
export function computeHash(content: string): string {
	return createHash("sha256").update(content, "utf8").digest("hex");
}

/**
 * Get the path to the metadata file for a feature directory
 */
export function getMetadataPath(featureDir: string): string {
	return path.join(featureDir, ".linear-metadata.json");
}

/**
 * Check if metadata file exists for a feature
 */
export function metadataExists(featureDir: string): boolean {
	return existsSync(getMetadataPath(featureDir));
}

/**
 * Load Linear metadata from feature directory
 * Returns undefined if file doesn't exist
 */
export function loadMetadata(featureDir: string): LinearMetadata | undefined {
	const metadataPath = getMetadataPath(featureDir);

	if (!existsSync(metadataPath)) {
		return undefined;
	}

	try {
		const content = readFileSync(metadataPath, "utf8");
		const metadata = JSON.parse(content) as LinearMetadata;

		// Basic validation
		if (!metadata.version || !metadata.featureId || !Array.isArray(metadata.tasks)) {
			throw new Error("Invalid metadata structure: missing required fields");
		}

		return metadata;
	} catch (error) {
		throw new Error(
			`Failed to load Linear metadata from ${metadataPath}: ${error instanceof Error ? error.message : String(error)}`,
		);
	}
}

/**
 * Create new Linear metadata for a feature
 */
export function createMetadata(featureId: string): LinearMetadata {
	return {
		$schema: "./contracts/metadata.schema.json",
		version: "1.0",
		featureId,
		tasks: [],
	};
}

/**
 * Save Linear metadata to feature directory
 * Uses atomic write (write temp → rename) to prevent corruption
 */
export function saveMetadata(featureDir: string, metadata: LinearMetadata): void {
	const metadataPath = getMetadataPath(featureDir);
	const tempPath = `${metadataPath}.tmp`;

	try {
		// Validate before writing
		if (!metadata.version || !metadata.featureId || !Array.isArray(metadata.tasks)) {
			throw new Error("Cannot save invalid metadata: missing required fields");
		}

		// Write to temp file first (atomic operation)
		const content = JSON.stringify(metadata, null, 2);
		writeFileSync(tempPath, content, "utf8");

		// Rename temp to final (atomic on most filesystems)
		if (existsSync(metadataPath)) {
			// On Windows, need to remove existing file first
			if (process.platform === "win32") {
				const backupPath = `${metadataPath}.backup`;
				writeFileSync(backupPath, readFileSync(metadataPath));
				writeFileSync(metadataPath, content, "utf8");
			} else {
				// On Unix, rename is atomic
				writeFileSync(metadataPath, content, "utf8");
			}
		} else {
			writeFileSync(metadataPath, content, "utf8");
		}

		// Clean up temp file
		if (existsSync(tempPath)) {
			// Ignore cleanup errors
			try {
				writeFileSync(tempPath, "");
			} catch {
				// Ignore
			}
		}
	} catch (error) {
		// Clean up temp file on error
		if (existsSync(tempPath)) {
			try {
				writeFileSync(tempPath, "");
			} catch {
				// Ignore cleanup errors
			}
		}

		throw new Error(
			`Failed to save Linear metadata to ${metadataPath}: ${error instanceof Error ? error.message : String(error)}`,
		);
	}
}

/**
 * Validate metadata structure
 * Returns array of validation errors (empty if valid)
 */
export function validateMetadata(metadata: LinearMetadata): string[] {
	const errors: string[] = [];

	// Check version
	if (!metadata.version || !metadata.version.match(/^\d+\.\d+$/)) {
		errors.push("Invalid version format (expected 'X.Y')");
	}

	// Check featureId
	if (!metadata.featureId || !metadata.featureId.match(/^\d{3}-[a-z0-9-]+$/)) {
		errors.push("Invalid featureId format (expected '###-feature-name')");
	}

	// Check tasks array
	if (!Array.isArray(metadata.tasks)) {
		errors.push("Tasks must be an array");
	} else {
		const taskIds = new Set<string>();
		for (const task of metadata.tasks) {
			// Check required fields
			if (!task.taskId || !task.linearSubIssueId || !task.linearSubIssueKey || !task.lastSync || !task.taskHash) {
				errors.push(`Task missing required fields: ${JSON.stringify(task)}`);
				continue;
			}

			// Check task ID format
			if (!task.taskId.match(/^T\d{3}$/)) {
				errors.push(`Invalid task ID format: ${task.taskId} (expected T###)`);
			}

			// Check for duplicates
			if (taskIds.has(task.taskId)) {
				errors.push(`Duplicate task ID: ${task.taskId}`);
			}
			taskIds.add(task.taskId);

			// Check Sub-Issue key format
			if (!task.linearSubIssueKey.match(/^[A-Z]{2,4}-\d+$/)) {
				errors.push(`Invalid Sub-Issue key format: ${task.linearSubIssueKey} (expected TEAM-###)`);
			}

			// Check hash format
			if (!task.taskHash.match(/^[a-f0-9]{64}$/)) {
				errors.push(`Invalid task hash format: ${task.taskHash} (expected 64-char hex)`);
			}

			// Check timestamp format (basic check)
			if (!task.lastSync.match(/^\d{4}-\d{2}-\d{2}T/)) {
				errors.push(`Invalid timestamp format: ${task.lastSync} (expected ISO 8601)`);
			}
		}
	}

	// Check linear (if present)
	if (metadata.linear) {
		const linear = metadata.linear;

		if (!linear.issueId || !linear.issueKey || !linear.teamKey || !linear.lastSync || !linear.specHash) {
			errors.push("Linear Issue metadata missing required fields");
		}

		if (linear.issueKey && !linear.issueKey.match(/^[A-Z]{2,4}-\d+$/)) {
			errors.push(`Invalid Issue key format: ${linear.issueKey} (expected TEAM-###)`);
		}

		if (linear.teamKey && !linear.teamKey.match(/^[A-Z]{2,4}$/)) {
			errors.push(`Invalid team key format: ${linear.teamKey} (expected 2-4 uppercase letters)`);
		}

		if (linear.specHash && !linear.specHash.match(/^[a-f0-9]{64}$/)) {
			errors.push(`Invalid spec hash format: ${linear.specHash} (expected 64-char hex)`);
		}

		if (linear.lastSync && !linear.lastSync.match(/^\d{4}-\d{2}-\d{2}T/)) {
			errors.push(`Invalid timestamp format: ${linear.lastSync} (expected ISO 8601)`);
		}
	}

	return errors;
}

import type { ContentChange, SanitizedContent } from "./types.js";

/**
 * Sanitize content for Linear sync
 * Two-phase pipeline: path sanitization → artifact filtering
 */
export function sanitizeContent(content: string, repoRoot: string): SanitizedContent {
	const changes: ContentChange[] = [];
	let sanitized = content;

	// Phase 1: Path Sanitization
	sanitized = sanitizePaths(sanitized, repoRoot, changes);

	// Phase 2: Artifact Filtering
	sanitized = filterArtifacts(sanitized, changes);

	// Phase 3: Cleanup
	sanitized = cleanupWhitespace(sanitized);

	return {
		original: content,
		sanitized,
		changes,
	};
}

/**
 * Phase 1: Sanitize absolute paths
 * - Convert paths starting with repo root to relative paths
 * - Remove paths outside repo root
 * - Preserve relative paths
 */
function sanitizePaths(content: string, repoRoot: string, changes: ContentChange[]): string {
	let result = content;

	// Pattern to match absolute paths
	// Matches: /Users/username/path/file.ext or ~/path/file.ext or C:\Users\path\file.ext
	const absolutePathPattern =
		/(?:^|\s)([\/~][\w\-_.\/\\]+\.[\w]+|[A-Z]:\\[\w\-_.\/\\]+\.[\w]+|\/[\w\-_.\/]+\/[\w\-_.]+)/gm;

	result = result.replace(absolutePathPattern, (match, path) => {
		const trimmed = match.trimStart();
		const leadingSpace = match.slice(0, match.length - trimmed.length);

		// Normalize path separators
		const normalizedPath = path.replace(/\\/g, "/");
		const normalizedRepoRoot = repoRoot.replace(/\\/g, "/");

		// Check if path starts with repo root
		if (normalizedPath.startsWith(normalizedRepoRoot)) {
			// Convert to relative path
			const relativePath = normalizedPath.slice(normalizedRepoRoot.length).replace(/^\//, "");

			changes.push({
				type: "absolute-path-relativized",
				original: path,
				replacement: relativePath,
			});

			return leadingSpace + relativePath;
		}

		// Check if path is a home directory path (~/)
		if (normalizedPath.startsWith("~/")) {
			// Remove home directory paths (outside repo)
			changes.push({
				type: "absolute-path-removed",
				original: path,
				replacement: "",
			});

			return leadingSpace; // Just the leading space
		}

		// Check if path looks like an absolute path outside repo
		if (normalizedPath.startsWith("/") || normalizedPath.match(/^[A-Z]:\//)) {
			// Remove absolute paths outside repo
			changes.push({
				type: "absolute-path-removed",
				original: path,
				replacement: "",
			});

			return leadingSpace; // Just the leading space
		}

		// Keep the match as-is (relative path or not a path)
		return match;
	});

	return result;
}

/**
 * Phase 2: Filter spec artifact references
 * Remove references to internal spec workflow files
 */
function filterArtifacts(content: string, changes: ContentChange[]): string {
	let result = content;

	// Patterns for spec workflow artifacts
	const artifactPatterns = [
		{ pattern: /\bplan\.md\b/gi, name: "plan.md" },
		{ pattern: /\btasks\.md\b/gi, name: "tasks.md" },
		{ pattern: /\bchecklist\.md\b/gi, name: "checklist.md" },
		{ pattern: /\bresearch\.md\b/gi, name: "research.md" },
		{ pattern: /\bdata-model\.md\b/gi, name: "data-model.md" },
		{ pattern: /\bquickstart\.md\b/gi, name: "quickstart.md" },
		{ pattern: /\bcontracts\/[\w\-_.]+/gi, name: "contracts/" },
		{ pattern: /\bchecklists\/[\w\-_.]+/gi, name: "checklists/" },
		{ pattern: /\/spec\s+(specify|clarify|plan|tasks|analyze|implement|checklist)/gi, name: "/spec commands" },
	];

	for (const { pattern, name } of artifactPatterns) {
		result = result.replace(pattern, (match) => {
			changes.push({
				type: "artifact-reference-removed",
				original: match,
				replacement: "",
			});

			return ""; // Remove the reference
		});
	}

	return result;
}

/**
 * Phase 3: Cleanup whitespace
 * Collapse multiple consecutive spaces
 */
function cleanupWhitespace(content: string): string {
	// Collapse multiple spaces to single space (but preserve newlines)
	return content
		.replace(/ {2,}/g, " ") // Multiple spaces → single space
		.replace(/\n{3,}/g, "\n\n") // Multiple blank lines → double newline
		.trim();
}

/**
 * Extract title from spec.md first heading
 */
export function extractTitle(specContent: string): string {
	// Match first markdown heading (# Title)
	const match = specContent.match(/^#\s+(.+)$/m);
	if (match && match[1]) {
		return match[1].trim();
	}

	// Fallback: use first line
	const firstLine = specContent.split("\n")[0];
	return firstLine ? firstLine.trim().slice(0, 100) : "Untitled Feature";
}

/**
 * Extract description from spec.md body
 * Returns content after the first heading
 */
export function extractDescription(specContent: string): string {
	// Find the first heading and return everything after it
	const lines = specContent.split("\n");
	let startIndex = 0;

	// Find first heading
	for (let i = 0; i < lines.length; i++) {
		if (lines[i].match(/^#\s+/)) {
			startIndex = i + 1;
			break;
		}
	}

	// Return content after heading
	return lines.slice(startIndex).join("\n").trim();
}

import type { ParsedTask } from "./types.js";

/**
 * Parse tasks from tasks.md file
 * Extracts task ID, title, description, and completion status
 */
export function parseTasks(tasksContent: string): ParsedTask[] {
	const tasks: ParsedTask[] = [];
	const taskSections = splitIntoTaskSections(tasksContent);

	for (const section of taskSections) {
		const task = parseTaskSection(section);
		if (task) {
			tasks.push(task);
		}
	}

	return tasks;
}

/**
 * Split tasks.md content into individual task sections
 * Tasks are delimited by "---" or "## Task" headers
 */
function splitIntoTaskSections(content: string): string[] {
	const sections: string[] = [];

	// Split by task headers (## Task T###: Title)
	const headerPattern = /^## Task (T\d{3}):/gm;
	const matches = Array.from(content.matchAll(headerPattern));

	if (matches.length === 0) {
		return sections;
	}

	for (let i = 0; i < matches.length; i++) {
		const match = matches[i];
		const startIndex = match.index!;
		const endIndex = i < matches.length - 1 ? matches[i + 1].index! : content.length;

		const section = content.slice(startIndex, endIndex).trim();
		sections.push(section);
	}

	return sections;
}

/**
 * Parse a single task section
 */
function parseTaskSection(section: string): ParsedTask | null {
	// Extract task ID from header: ## Task T001: Title
	const headerMatch = section.match(/^## Task (T\d{3}):(.+)$/m);
	if (!headerMatch) {
		return null;
	}

	const id = headerMatch[1].trim();
	const title = headerMatch[2].trim();

	// Extract completion status from checkbox: - [x] or - [ ]
	const checkboxMatch = section.match(/^-\s*\[([x ])\]/m);
	const isComplete = checkboxMatch ? checkboxMatch[1].toLowerCase() === "x" : false;

	// Extract description (everything after the header, excluding delimiter lines)
	const lines = section.split("\n");
	let descriptionStart = 1; // Skip header line

	// Skip to first line after header
	while (descriptionStart < lines.length && lines[descriptionStart].trim() === "") {
		descriptionStart++;
	}

	// Extract description, stopping at "---" delimiter if present
	let descriptionEnd = lines.length;
	for (let i = descriptionStart; i < lines.length; i++) {
		if (lines[i].trim() === "---") {
			descriptionEnd = i;
			break;
		}
	}

	const description = lines.slice(descriptionStart, descriptionEnd).join("\n").trim();

	return {
		id,
		title,
		description,
		isComplete,
		rawContent: section,
	};
}

/**
 * Detect duplicate task IDs in parsed tasks
 * Returns array of duplicate task IDs
 */
export function detectDuplicates(tasks: ParsedTask[]): string[] {
	const seen = new Set<string>();
	const duplicates = new Set<string>();

	for (const task of tasks) {
		if (seen.has(task.id)) {
			duplicates.add(task.id);
		}
		seen.add(task.id);
	}

	return Array.from(duplicates);
}

/**
 * Validate tasks.md format
 * Returns array of validation errors (empty if valid)
 */
export function validateTasksFormat(tasksContent: string): string[] {
	const errors: string[] = [];

	// Check for task headers
	const headerPattern = /^## Task (T\d{3}):/gm;
	const headers = Array.from(tasksContent.matchAll(headerPattern));

	if (headers.length === 0) {
		errors.push("No task headers found (expected format: ## Task T###: Title)");
		return errors;
	}

	// Parse tasks
	const tasks = parseTasks(tasksContent);

	// Check for duplicates
	const duplicates = detectDuplicates(tasks);
	if (duplicates.length > 0) {
		errors.push(`Duplicate task IDs found: ${duplicates.join(", ")}`);
	}

	// Validate each task
	for (const task of tasks) {
		// Check ID format
		if (!task.id.match(/^T\d{3}$/)) {
			errors.push(`Invalid task ID format: ${task.id} (expected T###)`);
		}

		// Check title not empty
		if (!task.title || task.title.trim().length === 0) {
			errors.push(`Task ${task.id} has empty title`);
		}

		// Warn if description is empty (not an error, but might be unintended)
		if (!task.description || task.description.trim().length === 0) {
			// This is OK - some tasks might have minimal description
		}
	}

	return errors;
}

/**
 * Extract task title from task section
 * Helper for creating Sub-Issue titles
 */
export function formatTaskTitle(task: ParsedTask): string {
	return `${task.id} - ${task.title}`;
}

