/**
 * Sync feature spec.md to Linear Issue
 * Creates new Issue or updates existing Issue
 */
export async function syncFeature(ctx: ExtensionCommandContext, paths: WorkflowPaths): Promise<void> {
	if (!paths.featureDir || !paths.featureSpec) {
		throw new Error("No active feature found. Run /spec specify first.");
	}

	// Check if spec.md exists (T010)
	if (!existsSync(paths.featureSpec)) {
		throw new Error(`spec.md not found at ${paths.featureSpec}. Run /spec specify first.`);
	}

	// Read spec.md content (T010)
	const specContent = readFileSync(paths.featureSpec, "utf8");

	// Compute hash for change detection (T010)
	const currentHash = computeHash(specContent);

	// Load or create metadata (T010)
	let metadata = loadMetadata(paths.featureDir);
	if (!metadata) {
		// Extract feature ID from directory name
		const featureId = path.basename(paths.featureDir);
		metadata = createMetadata(featureId);
	}

	// Check if spec has changed (T010, T012)
	const hasChanged = !metadata.linear || metadata.linear.specHash !== currentHash;

	if (!hasChanged) {
		ctx.ui.notify("No changes to sync - spec.md unchanged since last sync", "info");
		return;
	}

	// Sanitize content (T015)
	const sanitized = sanitizeContent(specContent, paths.repoRoot);

	// Extract title and description (T014)
	const title = extractTitle(specContent);
	const description = sanitized.sanitized;

	// Report sanitization changes
	if (sanitized.changes.length > 0) {
		ctx.ui.notify(
			`Sanitized content: ${sanitized.changes.length} changes (absolute paths, artifact references removed)`,
			"info",
		);
	}

	// Get team key (T013)
	const teamKey = await getOrPromptTeamKey(ctx, metadata);
	if (!teamKey) {
		throw new Error("Linear team key is required. Please provide a team key.");
	}

	try {
		if (!metadata.linear) {
			// Create new Issue (T011)
			await createLinearIssue(ctx, metadata, title, description, teamKey, currentHash, paths);
		} else {
			// Update existing Issue (T012)
			await updateLinearIssue(ctx, metadata, description, currentHash, paths);
		}
	} catch (error) {
		// Error handling (T017)
		handleSyncError(ctx, error, "sync-feature");
		throw error;
	}
}

