// Helper Functions

/**
 * Get team key from metadata or prompt user (T013)
 */
async function getOrPromptTeamKey(
	ctx: ExtensionCommandContext,
	metadata: LinearMetadata,
): Promise<string | undefined> {
	// If already have team key in metadata, use it
	if (metadata.linear?.teamKey) {
		return metadata.linear.teamKey;
	}

	// Prompt user for team key
	if (!ctx.hasUI || typeof ctx.ui.input !== "function") {
		return undefined;
	}

	const teamKey = await ctx.ui.input(
		"Enter Linear team key (e.g., SCH, ENG, PROD)",
		"Team key (2-4 uppercase letters)",
	);

	// Validate format
	if (teamKey && !teamKey.match(/^[A-Z]{2,4}$/)) {
		ctx.ui.notify(
			`Invalid team key format: ${teamKey}. Expected 2-4 uppercase letters (e.g., SCH, ENG).`,
			"warning",
		);
		return undefined;
	}

	return teamKey;
}

/**
 * Create new Linear Issue (T011)
 */
async function createLinearIssue(
	ctx: ExtensionCommandContext,
	metadata: LinearMetadata,
	title: string,
	description: string,
	teamKey: string,
	specHash: string,
	paths: WorkflowPaths,
): Promise<void> {
	ctx.ui.notify("Creating Linear Issue...", "info");

	// Call linear_issue tool via pi's tool invocation API
	// Note: This is a simplified version - actual implementation depends on pi's API
	const result = await invokeLinearTool(ctx, {
		action: "create",
		title,
		description,
		team: teamKey,
	});

	if (!result.success) {
		throw new Error(`Failed to create Linear Issue: ${result.error?.message || "Unknown error"}`);
	}

	// Update metadata with Issue info (T018 - defensive write)
	metadata.linear = {
		issueId: result.issue.id,
		issueKey: result.issue.identifier,
		teamKey,
		lastSync: new Date().toISOString(),
		specHash,
	};

	// Save metadata (atomic write)
	saveMetadata(paths.featureDir!, metadata);

	ctx.ui.notify(
		`✅ Created Linear Issue ${result.issue.identifier}\nURL: ${result.issue.url || "(URL not available)"}`,
		"info",
	);
}

/**
 * Update existing Linear Issue (T012)
 */
async function updateLinearIssue(
	ctx: ExtensionCommandContext,
	metadata: LinearMetadata,
	description: string,
	specHash: string,
	paths: WorkflowPaths,
): Promise<void> {
	if (!metadata.linear) {
		throw new Error("Cannot update Issue: no Linear metadata found");
	}

	ctx.ui.notify(`Updating Linear Issue ${metadata.linear.issueKey}...`, "info");

	// Call linear_issue tool to update
	const result = await invokeLinearTool(ctx, {
		action: "update",
		issue: metadata.linear.issueKey,
		description,
	});

	if (!result.success) {
		throw new Error(`Failed to update Linear Issue: ${result.error?.message || "Unknown error"}`);
	}

	// Update metadata (T018 - defensive write)
	metadata.linear.lastSync = new Date().toISOString();
	metadata.linear.specHash = specHash;

	// Save metadata (atomic write)
	saveMetadata(paths.featureDir!, metadata);

	ctx.ui.notify(`✅ Updated Linear Issue ${metadata.linear.issueKey}`, "info");
}

/**
 * Invoke Linear tool via pi's API
 * This is a placeholder - actual implementation depends on how pi exposes tool invocation
 */
async function invokeLinearTool(ctx: ExtensionCommandContext, params: any): Promise<any> {
	// TODO: Replace with actual pi tool invocation API
	// For now, this is a mock that will need to be replaced with the real implementation
	// The actual implementation will depend on how @fink-andreas/pi-linear-tools exposes its API

	// Example of what the real implementation might look like:
	// return await ctx.invokeToolCall('linear_issue', params);

	// Mock implementation for type-checking purposes
	throw new Error(
		"Linear tool invocation not yet implemented. Requires @fink-andreas/pi-linear-tools integration.",
	);
}

/**
 * Handle sync errors with actionable messages (T017)
 */
function handleSyncError(ctx: ExtensionCommandContext, error: unknown, operation: string): void {
	const message = error instanceof Error ? error.message : String(error);

	// Parse error types and provide actionable guidance
	if (message.includes("not found") || message.includes("404")) {
		ctx.ui.notify(
			`Error during ${operation}: Issue not found in Linear.\n` +
				"The Issue may have been deleted. Consider deleting .linear-metadata.json and resyncing.",
			"error",
		);
	} else if (message.includes("403") || message.includes("Forbidden") || message.includes("permission")) {
		ctx.ui.notify(
			`Error during ${operation}: Permission denied.\n` +
				"Verify you have access to the Linear team and workspace.",
			"error",
		);
	} else if (message.includes("network") || message.includes("ECONNREFUSED") || message.includes("timeout")) {
		ctx.ui.notify(
			`Error during ${operation}: Network error.\n` + "Check your connection and retry when Linear is available.",
			"error",
		);
	} else if (message.includes("rate limit")) {
		ctx.ui.notify(
			`Error during ${operation}: Linear API rate limit exceeded.\n` + "Wait a few minutes and try again.",
			"error",
		);
	} else {
		ctx.ui.notify(`Error during ${operation}: ${message}`, "error");
	}
}

